{
  "verses": [
    {
      "n": 21,
      "column": "left",
      "text": "Es eſmu Dahwidu man-\nnu Kalpu atraddis/ ar mannu\nſwehtu Etji eſmu es to ſiwaidiſe.\n"
    },
    {
      "n": 22,
      "column": "left",
      "text": "Ar to buhs manna Roh-\nka pastahwigi/ un mans Elſons\nwiꞥnu eespehzinahe.\n"
    },
    {
      "n": 23,
      "column": "left",
      "text": "Tee Eenaidneeki wiꞥnu\nne draggahs/ un tee Netaifni\nwiꞥnu ne nospaidiſs.\n"
    },
    {
      "n": 24,
      "column": "left",
      "text": "Bet es fatreeſchu wiꞥna\nPrettineekus wiꞥna Preekſcha/\nun mohzischu wiꞥna Eenaid-\nneekus.\n"
    },
    {
      "n": 25,
      "column": "left",
      "text": "Un manna Peetizziba un\nSchehlaſtiba ar wiꞥnu buhs/\nun wiꞥna Ragstaps eefsch man-\nna Wahrdn pa-augſtinahts.\n"
    },
    {
      "n": 26,
      "column": "left",
      "text": "Un es lifſchu wiꞥna Roh-\nku Juhrā/ un wiꞥna labbn Roh-\nku eefsch Uppehm.\n"
    },
    {
      "n": 27,
      "column": "left",
      "text": "Wiꞥsch nofauks mannt:\n"
    },
    {
      "n": 7,
      "column": "left",
      "text": "Tu eſti mans Tehws/ mans\nSTIPRAIS DEEWS/\nun mannas Pestiſchannas Pa-\ntwerums.\n"
    },
    {
      "n": 28,
      "column": "left",
      "text": "Ir es eezelfchu wiꞥnu par\nto pirmdſunnutchu/ par to wiſ-\nfu-augſtaku ſarp teem Kehni-\nneem wirs Semmes.\n"
    },
    {
      "n": 29,
      "column": "left",
      "text": "Es turreſchu wiꞥnam\nmannu Schehlaſtibu muhſchigi/\nun manna Derriha paliks wiꞥ-\nRam ſtipri pastahwigi.\n"
    },
    {
      "n": 30,
      "column": "left",
      "text": "Es dohſchu wiꞥnam\nnumu muhſchigi/ un (pa-\n"
    },
    {
      "n": 31,
      "column": "right",
      "text": "Rad wiꞥna Behrnt ma\nnn Bauſlibu atſtahj/ un eef\nmannahm Teeſahm ne ſtaiga.\n"
    },
    {
      "n": 32,
      "column": "right",
      "text": "Rad tee mannuſ Lifſ-\nmus faſahna/un mannuſ Ba-\nlus ne turr.\n"
    },
    {
      "n": 33,
      "column": "right",
      "text": "Tad peemekſchu eſ w-\nun Bahrtahpfcanas ar Rihtſ-\nnn wiꞥnu Noseegimus ar Mo-\nzibahm.\n"
    },
    {
      "n": 34,
      "column": "right",
      "text": "Bet mannu Schehlaſ-\nbu es no ta ne atreimſchu/un\nmannu Pateefbu es ne mell-\nſchu.\n"
    },
    {
      "n": 35,
      "column": "right",
      "text": "Es fawu Derribu ne f-\ngahnſchu/ un kaſ no mannah-\nLuhpahm iſrunnahts/ to es u-\npahrgrobsſchu.\n"
    },
    {
      "n": 36,
      "column": "right",
      "text": "Es efiniu weenkaht p-\nmannas Swehtibas ſwehrejs/e-\nDahwidam ne melloſchu.\n"
    },
    {
      "n": 37,
      "column": "right",
      "text": "Wiꞥna Dſimmums buh-\nmuhſchigi/ un wiꞥna Gohda-\nKrehſlis manna Preekſcha ka t-\nSaule.\n"
    },
    {
      "n": 38,
      "column": "right",
      "text": "Wiꞥch taps muhſchia-\nſtiprinahts/ ka tas Mehnes/ uu-\nbuhs pastahwigſ/ ka tas Leezi-\nneeks ceſſch Badebbeſim/ Sela-\n"
    },
    {
      "n": 39,
      "column": "right",
      "text": "Bet (nu) eſti tu wiꞥnu-\natſtuhmis/ un atmettis/ tu eſ-\napſkaiteeſ prett tawu Swaiditu-\n"
    },
    {
      "n": 40,
      "column": "right",
      "text": "Tu eſti tawa Kalpa Der-\nribu iſnihztinahe/ wiꞥna Krohn-\neſti tu pee Semmes ſamaitajs.\n"
    },
    {
      "n": 41,
      "column": "right",
      "text": "Tu falaust wiſſas wiꞥu-\nSehtas/ wiꞥnu Stiprumuseſſ-\ntu nogahsis.\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
